import { 
  ActionRowBuilder, 
  ButtonBuilder, 
  ButtonStyle, 
  EmbedBuilder, 
  Message, 
  TextChannel 
} from 'discord.js';
import type { PrefixCommand } from '../../ai/commandRegistry.js';

export const prefixCommand: PrefixCommand = {
  trigger: 'setup-register',
  description: 'Injeta a interface de registro interativa.',
  async execute(message: Message) {
    if (message.author.id !== '892469618063589387') return;

    const REG_CHANNEL_ID = '1495985460281999522';
    const channel = message.guild?.channels.cache.get(REG_CHANNEL_ID) as TextChannel;

    if (!channel) return message.reply('❌ Erro: Canal de registro não encontrado no cache.');

    try {
      // 1. Limpeza rápida do canal (apenas o que for possível)
      await channel.bulkDelete(20, true).catch(() => {});

      // 2. Construção da Interface
      const embed = new EmbedBuilder()
        .setTitle('🔰 DATABASE DE ACESSO - FAW')
        .setColor(0x800080)
        .setThumbnail(message.guild?.iconURL() || null)
        .setDescription(
          '### 🛡️ Autenticação Necessária\n' +
          'Seja bem-vindo ao laboratório **FAW**. Seu acesso atual está restrito.\n\n' +
          'Para desbloquear os setores de **Engenharia Reversa, Malware Lab e Coding**, realize o registro formal clicando no botão abaixo.\n\n' +
          '**O que será configurado:**\n' +
          '• Seu Codinome operacional.\n' +
          '• Adesão opcional à Tag de Lealdade `[FAW]` (Cor Roxa).\n' +
          '• Atribuição de cargos de acesso nível 1.'
        )
        .setFooter({ text: 'Sistema Operacional FAW | Protocolo v5.0' });

      const row = new ActionRowBuilder<ButtonBuilder>().addComponents(
        new ButtonBuilder()
          .setCustomId('faw_start_reg')
          .setLabel('Iniciar Protocolo de Registro')
          .setStyle(ButtonStyle.Success)
          .setEmoji('🛡️')
      );

      // 3. Envio Direto
      await channel.send({ embeds: [embed], components: [row] });

      // 4. Feedback e Limpeza do comando
      if (message.channel.id === REG_CHANNEL_ID) {
        await message.delete().catch(() => {});
      } else {
        await message.reply('✅ **Interface injetada com sucesso** em <#1495985460281999522>.');
      }

      // 5. Sincronização Silenciosa de quem está sem cargo (Background)
      const UNREG_ROLE_ID = '1495985456943202327';
      const MEMBER_ROLE_ID = '1493095650555068576';
      const members = await message.guild!.members.fetch();
      members.forEach(m => {
        if (!m.user.bot && !m.roles.cache.has(MEMBER_ROLE_ID) && !m.roles.cache.has(UNREG_ROLE_ID)) {
          m.roles.add(UNREG_ROLE_ID).catch(() => {});
        }
      });

    } catch (err: any) {
      console.error(err);
      await message.reply(`❌ Erro crítico ao injetar interface: ${err.message}`);
    }
  }
};
