import { 
  ActionRowBuilder, 
  ButtonBuilder, 
  ButtonStyle, 
  EmbedBuilder, 
  Message, 
  TextChannel 
} from 'discord.js';
import type { PrefixCommand } from '../../ai/commandRegistry.js';

export const prefixCommand: PrefixCommand = {
  trigger: 'setup-register',
  description: 'Injeta a interface de registro via API Direta.',
  async execute(message: Message) {
    if (message.author.id !== '892469618063589387') return;

    const REG_CHANNEL_ID = '1495985460281999522';

    try {
      // 1. Forçar busca do canal direto na API (ignora cache)
      const channel = await message.guild?.channels.fetch(REG_CHANNEL_ID) as TextChannel;

      if (!channel) {
        return message.reply('❌ Erro Crítico: Canal não encontrado na API do Discord.');
      }

      // 2. Criar a interface básica (sem firulas para não dar erro de link/imagem)
      const embed = new EmbedBuilder()
        .setTitle('🔰 DATABASE DE ACESSO - FAW')
        .setColor(0x800080)
        .setDescription(
          '### 🛡️ Autenticação Requerida\n' +
          'Bem-vindo ao laboratório **FAW**.\n\n' +
          'Clique no botão abaixo para iniciar seu registro e desbloquear os setores de engenharia e desenvolvimento.'
        )
        .setFooter({ text: 'Sistema de Segurança FAW' });

      const row = new ActionRowBuilder<ButtonBuilder>().addComponents(
        new ButtonBuilder()
          .setCustomId('faw_start_reg')
          .setLabel('Iniciar Registro')
          .setStyle(ButtonStyle.Success)
          .setEmoji('🛡️')
      );

      // 3. Tentar o envio
      const sent = await channel.send({ embeds: [embed], components: [row] });

      if (sent) {
        await message.reply('✅ **Sucesso!** Interface injetada no canal de registro.').then(m => setTimeout(() => m.delete(), 3000));
        await message.delete().catch(() => {});
      }

    } catch (err: any) {
      console.error('ERRO NO SETUP:', err);
      // Se falhar, me avise no canal onde dei o comando
      await message.reply(`❌ **FALHA NO ENVIO:** ${err.message}`);
    }
  }
};
